const path = require\('path'\);
const { chromium } = require\('playwright'\);
\(async \(\) => {
  const browser = await chromium.launch\(\);
  const page = await browser.newPage\({ viewport: { width: 1920, height: 1080 } }\);
  await page.goto\('http://127.0.0.1:8188'\);
  await page.waitForTimeout\(4000\);
  // Open sidebar
  const bolt = page.locator\('.pi-bolt'\).first\(\);
  if \(await bolt.count\(\) > 0\) await bolt.click\(\);
  await page.waitForTimeout\(2000\);

  // Check data attributes on messages
  const attrs = await page.evaluate\(\(\) => {
    const el = document.querySelector\('#sd-messages'\);
    if \(!el\) return 'messages not found';
    return { font: el.dataset.font, align: el.dataset.align, mode: el.dataset.mode };
  }\);
  console.log\('Initial state:', JSON.stringify\(attrs\)\);

  // Click the large A \(font up\) button
  const readbarBtns = await page.locator\('.sd-readbar__btn'\).all\(\);
  console.log\('Readbar buttons found:', readbarBtns.length\);

  // Click font up \(2nd button\)
  if \(readbarBtns.length >= 2\) {
    await readbarBtns[1].click\(\);
    const after = await page.evaluate\(\(\) => document.querySelector\('#sd-messages'\).dataset.font\);
    console.log\('After font up:', after\);
  }

  // Click compact mode \(last button\)
  if \(readbarBtns.length >= 7\) {
    await readbarBtns[6].click\(\);
    const after = await page.evaluate\(\(\) => document.querySelector\('#sd-messages'\).dataset.mode\);
    console.log\('After compact click:', after\);
  }

  // Click center align \(4th button, index 3\)
  if \(readbarBtns.length >= 4\) {
    await readbarBtns[3].click\(\);
    const after = await page.evaluate\(\(\) => document.querySelector\('#sd-messages'\).dataset.align\);
    console.log\('After center align:', after\);
  }

  // Verify localStorage
  const storage = await page.evaluate\(\(\) => \({
    font: localStorage.getItem\('sd-font'\),
    align: localStorage.getItem\('sd-align'\),
    mode: localStorage.getItem\('sd-mode'\),
  }\)\);
  console.log\('localStorage:', JSON.stringify\(storage\)\);

  // Take screenshot with compact + large font + center
  await page.waitForTimeout\(500\);
  const outPath = path.join\(process.env.TEMP, 'comfyui_readbar_active.png'\);
  await page.screenshot\({
    path: outPath,
    clip: { x: 0, y: 0, width: 350, height: 1080 }
  }\);
  console.log\('Active state screenshot saved'\);
  await browser.close\(\);
}\)\(\);
