const path = require\('path'\);
const { chromium } = require\('playwright'\);
\(async \(\) => {
  const browser = await chromium.launch\(\);
  const page = await browser.newPage\({ viewport: { width: 1920, height: 1080 } }\);
  await page.goto\('http://127.0.0.1:8188'\);
  await page.waitForTimeout\(4000\);
  // Open sidebar
  const bolt = page.locator\('.pi-bolt'\).first\(\);
  if \(await bolt.count\(\) > 0\) await bolt.click\(\);
  await page.waitForTimeout\(2000\);

  // Add some sample messages to the chat so we can see the difference
  await page.evaluate\(\(\) => {
    const el = document.querySelector\('#sd-messages'\);
    const msgs = [
      { role: 'user', text: 'Can you analyze my workflow and suggest improvements?' },
      { role: 'agent', text: 'I\\\\'ve analyzed your workflow. Here\\\\'s what I found:\\\\n\\\\nYour pipeline uses a **KSampler** with 20 Euler steps at CFG 8.0. The **CLIP Text Encode** nodes are properly connected for both positive and negative prompts.\\\\n\\\\nI\\\\'d recommend switching to **DPM++ 2M Karras** sampler — it produces comparable quality in fewer steps, which could save you about 30% render time.' },
      { role: 'user', text: 'What about the resolution?' },
      { role: 'agent', text: 'Your **Empty Latent Image** is set to 512x512, which is the native resolution for SD 1.5 models. That\\\\'s correct for your current checkpoint.\\\\n\\\\nIf you want higher resolution output, I\\\\'d suggest adding an upscaler node after the VAE decode rather than increasing the latent size directly — that avoids the composition artifacts you get from generating at non-native resolutions.' },
    ];
    for \(const m of msgs\) {
      const div = document.createElement\('div'\);
      div.className = 'sd-message sd-message--' + m.role;
      if \(m.role !== 'system'\) {
        const label = document.createElement\('span'\);
        label.className = 'sd-message__label';
        label.textContent = m.role === 'user' ? 'You' : 'Agent';
        div.appendChild\(label\);
      }
      const body = document.createElement\('div'\);
      body.className = 'sd-message__body sd-text-body';
      // Simple paragraph rendering
      const paras = m.text.split\('\\\\n\\\\n'\);
      for \(const para of paras\) {
        const p = document.createElement\('p'\);
        // Handle bold
        const parts = para.split\(/\(\\\\*\\\\*[^*]+\\\\*\\\\*\)/\);
        for \(const part of parts\) {
          if \(part.startsWith\('**'\) && part.endsWith\('**'\)\) {
            const b = document.createElement\('strong'\);
            b.className = 'sd-text-bold';
            b.textContent = part.slice\(2, -2\);
            p.appendChild\(b\);
          } else {
            p.appendChild\(document.createTextNode\(part\)\);
          }
        }
        body.appendChild\(p\);
      }
      div.appendChild\(body\);
      el.appendChild\(div\);
    }
  }\);
  await page.waitForTimeout\(500\);

  // Screenshot 1: COMFORT mode \(default\)
  await page.evaluate\(\(\) => {
    const el = document.querySelector\('#sd-messages'\);
    el.dataset.mode = 'comfort';
    el.dataset.font = 'm';
    el.dataset.align = 'left';
  }\);
  await page.waitForTimeout\(300\);
  await page.screenshot\({
    path: path.join\(process.env.TEMP, 'comfyui_comfort.png'\),
    clip: { x: 45, y: 0, width: 310, height: 1080 }
  }\);
  console.log\('Comfort screenshot saved'\);

  // Screenshot 2: COMPACT mode
  await page.evaluate\(\(\) => {
    const el = document.querySelector\('#sd-messages'\);
    el.dataset.mode = 'compact';
  }\);
  await page.waitForTimeout\(300\);
  await page.screenshot\({
    path: path.join\(process.env.TEMP, 'comfyui_compact.png'\),
    clip: { x: 45, y: 0, width: 310, height: 1080 }
  }\);
  console.log\('Compact screenshot saved'\);

  await browser.close\(\);
}\)\(\);
